#include <stdio.h>

// Recursive function to find GCD using Euclidean Algorithm
int gcd(int a, int b) {
    if (b == 0)
        return a; // Base case
    return gcd(b, a % b); // Recursive case
}

int main() {
    int A, B;

    // Read two integers
    scanf("%d %d", &A, &B);

    // Calculate and print GCD
    printf("%d\n", gcd(A, B));

    return 0;
}

