import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    static boolean primeGen(int n) {
        if (n < 2) return false;
        for (int i = 2; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t--> 0) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            for (int i = a; i <= b; i++) {
                if (primeGen(i)) {
                    System.out.println(i);
                }
            }
        }
        sc.close();
    }
}

