const readline = require('readline');

// Function to generate primes in a given range using a segmented sieve
function generatePrimesInRange(m, n) {
    const range = n - m + 1;
    const isPrime = Array(range).fill(true);

    // Mark non-primes for numbers less than or equal to √n
    for (let i = 2; i * i <= n; i++) {
        let start = Math.max(i * i, Math.ceil(m / i) * i);
        for (let j = start; j <= n; j += i) {
            isPrime[j - m] = false;
        }
    }

    // Collect all primes in the range
    const primes = [];
    for (let i = 0; i < range; i++) {
        if (isPrime[i] && (m + i) > 1) {
            primes.push(m + i);
        }
    }
    return primes;
}

// Read input using readline
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let inputLines = [];
rl.on('line', (line) => {
    inputLines.push(line);
});

rl.on('close', () => {
    const t = parseInt(inputLines[0]);
    const results = [];

    for (let i = 1; i <= t; i++) {
        const [m, n] = inputLines[i].split(' ').map(Number);
        const primes = generatePrimesInRange(m, n);
        results.push(primes.join('\n'));
    }

    // Print results separated by an empty line
    console.log(results.join('\n\n'));
